const KING_BASE64 = "data:image/png;base64,";

const kingImage = new Image();
kingImage.src = KING_BASE64;

function drawKingPieceSimple(ctx, cx, cy) {
  const r = 24;

  // --- base ---
  const gradient = ctx.createRadialGradient(
    cx - 5, cy - 6, 4,
    cx, cy, r
  );
  gradient.addColorStop(0, "#faf3d0");
  gradient.addColorStop(1, "#e0c676");

  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, Math.PI * 2);
  ctx.fillStyle = gradient;
  ctx.fill();

  // --- outer border ---
  ctx.lineWidth = 2;
  ctx.strokeStyle = "#6f5a1e";
  ctx.stroke();

  // ✅ --- inner circle (new) ---
  ctx.beginPath();
  ctx.arc(cx, cy, r - 8, 0, Math.PI * 2);
  ctx.strokeStyle = "rgba(90, 71, 21, 0.6)";
  ctx.lineWidth = 1.5;
  ctx.stroke();

  // --- cross ---
  ctx.strokeStyle = "#5a4715";
  ctx.lineWidth = 3;
  ctx.lineCap = "round";

  const crossSize = 10;

  ctx.beginPath();
  ctx.moveTo(cx, cy - crossSize);
  ctx.lineTo(cx, cy + crossSize);
  ctx.stroke();

  ctx.beginPath();
  ctx.moveTo(cx - crossSize, cy);
  ctx.lineTo(cx + crossSize, cy);
  ctx.stroke();

  // --- highlight ---
  ctx.beginPath();
  ctx.arc(cx - 6, cy - 7, 9, 0, Math.PI * 2);
  ctx.fillStyle = "rgba(255,255,255,0.25)";
  ctx.fill();
}

function drawKingPieceYtreza(ctx, cx, cy) {
    const imgSize = 54;
    ctx.drawImage(
        kingImage,
        cx - imgSize / 2,
        cy - imgSize / 2,
        imgSize,
        imgSize
    );
}

function drawKingPiece(ctx, cx, cy) {
    if(king_design === "Ytreza")
        drawKingPieceYtreza(ctx, cx, cy);
    else
        drawKingPieceSimple(ctx, cx, cy);
}

function drawPawnPieceYtreza(ctx, cx, cy, color = "black") {
  const r = 23;

  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, Math.PI * 2);
  ctx.fillStyle = color === "black" ? "#2a2a2a" : "#edede8";
  ctx.fill();

  ctx.lineWidth = 2;
  ctx.strokeStyle = color === "black" ? "#444" : "#aaa";
  ctx.stroke();
}


function drawPawnPieceFancy(ctx, cx, cy, color = "black") {
  const r = 23;

  ctx.beginPath();
  ctx.arc(cx, cy, r, 0, Math.PI * 2);
  ctx.fillStyle = color === "black" ? "#1e1e1e" : "#f6f1e8";
  ctx.fill();

  ctx.lineWidth = 2;
  ctx.strokeStyle = color === "black" ? "#555" : "#777";
  ctx.stroke();

  ctx.beginPath();
  ctx.arc(cx - 6, cy - 7, 8, 0, Math.PI * 2);
  ctx.fillStyle = color === "black"
    ? "rgba(255,255,255,0.08)"
    : "rgba(255,255,255,0.45)";
  ctx.fill();
}

function drawPawnPiece(ctx, cx, cy, color = "black") {
    if(king_design === "Ytreza")
        drawPawnPieceYtreza(ctx, cx, cy, color);
    else
        drawPawnPieceFancy(ctx, cx, cy, color);
}
